mapper.select:
select * from ST_STBPRP_B_STCD


        and STCD in

            #{stcd}



        and TYPE in

            #{type}



        and SOURCE in

            #{source}

mapper.update:
UPDATE st_stbprp_b_stcd a
SET
a.ZTM = (SELECT v.TM FROM st_river_r v WHERE v.STCD = a.STCD ORDER BY v.TM DESC LIMIT 1),
a.UPZ = (SELECT v.Z FROM st_river_r v WHERE v.STCD = a.STCD ORDER BY v.TM DESC LIMIT 1)


        a.TYPE = #{type}


AND EXISTS (SELECT 1 FROM st_river_r v WHERE v.STCD = a.STCD);

UPDATE st_stbprp_b_stcd a SET a.ZTM = (SELECT v.TM FROM st_was_r v WHERE v.STCD = a.STCD ORDER BY v.TM DESC LIMIT 1), a.UPZ = (SELECT v.UPZ FROM st_was_r v WHERE v.STCD = a.STCD ORDER BY v.TM DESC LIMIT 1), a.DWZ = (SELECT v.DWZ FROM st_was_r v WHERE v.STCD = a.STCD ORDER BY v.TM DESC LIMIT 1)
a.TYPE = #{type}
AND EXISTS (SELECT 1 FROM st_was_r v WHERE v.STCD = a.STCD);

